module top_module(
    input [15:0] minuend,
    input [15:0] subtrahend,
    input control,
    output reg [15:0] result  // Change wire to reg to use in always block
);wire [15:0] twos_complement_subtrahend;
      wire _n01 = (~subtrahend)[0] ^ 1[0];
  wire _c01 = (~subtrahend)[0] & 1[0];
  wire _n02 = (~subtrahend)[1] ^ 1[1] ^ _c01;
  wire _c02 = ((~subtrahend)[1] & 1[1]) | ((~subtrahend)[1] & _c01) | (1[1] & _c01);
  wire _n03 = (~subtrahend)[2] ^ 1[2] ^ _c02;
  wire _c03 = ((~subtrahend)[2] & 1[2]) | ((~subtrahend)[2] & _c02) | (1[2] & _c02);
  wire _n04 = (~subtrahend)[3] ^ 1[3] ^ _c03;
  wire _c04 = ((~subtrahend)[3] & 1[3]) | ((~subtrahend)[3] & _c03) | (1[3] & _c03);
  assign twos_complement_subtrahend = {_n01, _n02, _n03, _n04};

    always @(*) begin
        if (control) begin
            result = minuend + twos_complement_subtrahend;
        end else begin
            result = minuend + subtrahend;
        end
    end

endmodule
